class Node:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

class BinaryTree:
    def __init__(self, root=None):
        self.root = root

    def get_depth(self):
        return self._calculate_depth_recursive(self.root)

    def _calculate_depth_recursive(self, node):
        if node is None:
            return 0

        left_depth = self._calculate_depth_recursive(node.left)
        right_depth = self._calculate_depth_recursive(node.right)

        return 1 + max(left_depth, right_depth)
